// Read what the SmallTV asked for and build the source URLs.
// Symbols that look like a cash.ch listing key (valor-marketId-currencyId,
// e.g. 147478611-246-333) are routed to cash.ch; everything else goes to Yahoo.
const q = $input.first().json.query || {};
const symbol = (q.symbol || 'AAPL').toString().trim();
const range = (q.range || '1d').toString().toLowerCase();
const points = Math.max(0, parseInt(q.points || '48')) || 48;

const isCash = /^\d+-\d+-\d+$/.test(symbol);

// cash.ch: daily closes to request per timeframe. The server trims to the
// newest N inside a fixed catch-all from/to window; history holds ~6 months.
const daysMap = { '1d':2, '5d':5, '1mo':22, '3mo':65, '6mo':130, 'ytd':130, '1y':260, '2y':400, '5y':400, 'max':400 };
const days = daysMap[range] || 130;

const gql = 'https://www.cash.ch/_/api/graphql/prod?query=';
const quoteQ = `query{quoteList(listingKeys:"${symbol}"){quoteList{edges{node{...on Instrument{lval iNetVperprV perfPercentage mCur mShortName}}}}}}`;
const chartQ = `query{integration{solid{chart(listingKey:"${symbol}" frequency:"1d" from:"2020-01-01" to:"2100-01-01" max:"${days}"){timeserie{prices{close}}}}}}`;

// Yahoo: map the chart timeframe to a sensible candle interval.
const intervalMap = { '1d':'5m', '5d':'30m', '1mo':'1d', '3mo':'1d', '6mo':'1d', 'ytd':'1d', '1y':'1wk', '2y':'1wk', '5y':'1mo', 'max':'1mo' };
const interval = intervalMap[range] || '1d';

return [{ json: {
  symbol, range, points, isCash,
  cashQuoteUrl: gql + encodeURIComponent(quoteQ),
  cashChartUrl: gql + encodeURIComponent(chartQ),
  yahooUrl: `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(symbol)}?range=${encodeURIComponent(range)}&interval=${interval}`
} }];

// Transform the two cash.ch GraphQL payloads into the SmallTV contract.
// Every numeric quote field is a JSON string, so parseFloat is mandatory:
// the firmware rejects string-encoded numbers.
const p = $('Prepare').first().json;
const quote = $('Cash Quote').first().json;
let chart = {};
try { chart = $('Cash Chart').first().json; } catch (e) {}

let node = null;
try { node = quote.data.quoteList.quoteList.edges[0].node; } catch (e) {}

const price = node && node.lval != null ? parseFloat(node.lval) : null;
const change = node && node.iNetVperprV != null ? parseFloat(node.iNetVperprV) : null;
const changePct = node && node.perfPercentage != null ? parseFloat(node.perfPercentage) : null;

let closes = [];
try { closes = chart.data.integration.solid.chart.timeserie.prices.map(x => x.close).filter(v => v != null); } catch (e) {}

function downsample(arr, n) {
  if (n <= 0 || arr.length <= n) return arr;
  const out = [];
  const step = (arr.length - 1) / (n - 1);
  for (let i = 0; i < n; i++) out.push(arr[Math.round(i * step)]);
  return out;
}
const round = (v, d) => v == null || isNaN(v) ? null : Math.round(v * Math.pow(10, d)) / Math.pow(10, d);
const spark = downsample(closes, p.points).map(v => round(v, 4));

const cur = { USD:'$', EUR:'\u20ac', GBP:'\u00a3', JPY:'\u00a5', CHF:'CHF ' };

return [{ json: {
  symbol: p.symbol,
  name: (node && node.mShortName) || p.symbol,
  price: round(price, 4),
  currency: node && node.mCur ? (cur[node.mCur] || node.mCur + ' ') : '',
  change: round(change, 4),
  changePct: round(changePct, 2),
  spark,
  range: p.range.toUpperCase(),
  ok: price != null && !isNaN(price)
}}];

// Transform the Yahoo chart payload into the SmallTV contract.
const p = $('Prepare').first().json;
const r = $input.first().json;
const res = r && r.chart && r.chart.result && r.chart.result[0];

if (!res || !res.meta) {
  return [{ json: { symbol: p.symbol, ok: false } }];
}
const meta = res.meta;
const price = meta.regularMarketPrice;
const prev = (meta.chartPreviousClose != null ? meta.chartPreviousClose : meta.previousClose);

let closes = [];
try { closes = res.indicators.quote[0].close.filter(v => v != null); } catch (e) {}

function downsample(arr, n) {
  if (n <= 0 || arr.length <= n) return arr;
  const out = [];
  const step = (arr.length - 1) / (n - 1);
  for (let i = 0; i < n; i++) out.push(arr[Math.round(i * step)]);
  return out;
}
const round = (v, d) => v == null ? null : Math.round(v * Math.pow(10, d)) / Math.pow(10, d);
const spark = downsample(closes, p.points).map(v => round(v, 4));

const change = (price != null && prev != null) ? price - prev : null;
const changePct = (change != null && prev) ? (change / prev * 100) : null;
const cur = { USD:'$', EUR:'\u20ac', GBP:'\u00a3', JPY:'\u00a5', CHF:'CHF ' };

return [{ json: {
  symbol: p.symbol,
  name: meta.shortName || meta.symbol || p.symbol,
  price: round(price, 4),
  currency: cur[meta.currency] || (meta.currency || ''),
  change: round(change, 4),
  changePct: round(changePct, 2),
  spark,
  range: p.range.toUpperCase(),
  ok: price != null
}}];
